import { Platform } from 'react-native';

const API_URL = 'https://api.example.com';
const LOCAL_DEVICE_IP = 'http://192.168.x.x';

const defaultHeaders = {
  'Content-Type': 'application/json',
  Accept: 'application/json',
};

export const apiRequest = async (endpoint, method = 'GET', body) => {
  try {
    const response = await fetch(`${API_URL}${endpoint}`, {
      method,
      headers: defaultHeaders,
      body: body ? JSON.stringify(body) : null,
    });
    return response.json();
  } catch (error) {
    console.error('API Request Error:', error);
    throw error;
  }
};

export const localDeviceRequest = async (deviceEndpoint, method = 'GET', body) => {
  try {
    const url = `${Platform.select({
      ios: 'http://',
      android: 'http://',
    })}${LOCAL_DEVICE_IP}${deviceEndpoint}`;
    const response = await fetch(url, {
      method,
      headers: defaultHeaders,
      body: body ? JSON.stringify(body) : null,
    });
    return response.json();
  } catch (error) {
    console.error('Local Device Request Error:', error);
    throw error;
  }
};